import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Navbar() {
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <nav className="sticky top-0 z-50 bg-gradient-to-r from-blue-600 via-purple-600 to-pink-500 shadow-lg">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">

          {/* Logo */}
          <Link to={token ? '/home' : '/'} className="flex items-center gap-2">
            <span className="text-3xl">🎉</span>
            <span className="text-white text-xl font-bold tracking-wide">EventHub</span>
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center gap-2">
            {token ? (
              <>
                <Link to="/home" className="text-white/90 hover:text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition">
                  Home
                </Link>
                <Link to="/my-bookings" className="text-white/90 hover:text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition">
                  My Bookings
                </Link>
                {user.role === 'admin' && (
                  <Link to="/admin" className="text-white/90 hover:text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition">
                    Admin
                  </Link>
                )}
                <div className="flex items-center gap-3 ml-4">
                  <span className="bg-white/20 text-white px-4 py-2 rounded-full text-sm font-medium">
                    👤 {user.name}
                  </span>
                  <button onClick={handleLogout} className="bg-red-500 hover:bg-red-600 text-white px-4 py-2 rounded-full text-sm font-semibold transition">
                    Logout
                  </button>
                </div>
              </>
            ) : (
              <>
                <Link to="/login" className="text-white/90 hover:text-white hover:bg-white/20 px-4 py-2 rounded-lg font-medium transition">
                  Login
                </Link>
                <Link to="/register" className="bg-white text-purple-600 hover:bg-gray-100 px-5 py-2 rounded-full font-semibold transition">
                  Sign Up Free
                </Link>
              </>
            )}
          </div>

          {/* Mobile Menu Button */}
          <button onClick={() => setMenuOpen(!menuOpen)} className="md:hidden text-white text-2xl">
            {menuOpen ? '✕' : '☰'}
          </button>
        </div>

        {/* Mobile Menu */}
        {menuOpen && (
          <div className="md:hidden pb-4 flex flex-col gap-2">
            {token ? (
              <>
                <Link to="/home" onClick={() => setMenuOpen(false)} className="text-white hover:bg-white/20 px-4 py-2 rounded-lg">Home</Link>
                <Link to="/my-bookings" onClick={() => setMenuOpen(false)} className="text-white hover:bg-white/20 px-4 py-2 rounded-lg">My Bookings</Link>
                {user.role === 'admin' && (
                  <Link to="/admin" onClick={() => setMenuOpen(false)} className="text-white hover:bg-white/20 px-4 py-2 rounded-lg">Admin</Link>
                )}
                <button onClick={handleLogout} className="text-left text-white bg-red-500 hover:bg-red-600 px-4 py-2 rounded-lg">Logout</button>
              </>
            ) : (
              <>
                <Link to="/login" onClick={() => setMenuOpen(false)} className="text-white hover:bg-white/20 px-4 py-2 rounded-lg">Login</Link>
                <Link to="/register" onClick={() => setMenuOpen(false)} className="text-white hover:bg-white/20 px-4 py-2 rounded-lg">Sign Up</Link>
              </>
            )}
          </div>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
